1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type Incident = { cause: string; damages: Damage[] };
4	export type QuoteStep = { op: "quote"; items: Item[] };
5	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	export type Step = QuoteStep | ClaimStep;
7	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	export type QuoteResult = { premium: number };
9	export type ClaimResult = { payout: number; remainingCap: number };
10	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	
25	type Customer = { yearsWithMHPCO: number };
26	const COMPONENT_UNIT_BASE = 25;
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE = 60;
29	
30	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	};
36	
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const isKnownMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
51	
52	type BillingGroup = { base: number; cursed: boolean; enchantment: number };
53	
54	const componentBundleBase = (count: number): number => {
55	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
56	  return count * COMPONENT_UNIT_BASE;
57	};
58	
59	const mainItemGroup = (item: Item): BillingGroup => ({
60	  base: MAIN_ITEM_BASE_PREMIUM[item.type],
61	  cursed: item.cursed === true,
62	  enchantment: item.enchantment ?? 0,
63	});
64	
65	const componentBundleGroup = (count: number): BillingGroup => ({
66	  base: componentBundleBase(count),
67	  cursed: false,
68	  enchantment: 0,
69	});
70	
71	const tallyComponents = (items: Item[]): Map<string, number> => {
72	  const counts = new Map<string, number>();
73	  for (const item of items) {
74	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
75	  }
76	  return counts;
77	};
78	
79	const billingGroups = (items: Item[]): BillingGroup[] => {
80	  const mainItems: Item[] = [];
81	  const components: Item[] = [];
82	  for (const item of items) {
83	    if (isComponent(item)) components.push(item);
84	    else if (isKnownMainItem(item)) mainItems.push(item);
85	    else throw new Error(`Unknown item type: ${item.type}`);
86	  }
87	  const componentGroups = [...tallyComponents(components).values()].map(componentBundleGroup);
88	  return [...mainItems.map(mainItemGroup), ...componentGroups];
89	};
90	
91	const groupPremium = ({ base, cursed, enchantment }: BillingGroup): number => {
92	  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
93	  const enchantmentSurcharge =
94	    enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
95	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
96	  return base + curseSurcharge + enchantmentSurcharge + firstInsuranceSurcharge;
97	};
98	
99	const sumGroupPremiums = (groups: BillingGroup[]): number =>
100	  groups.reduce((sum, g) => sum + groupPremium(g), 0);
101	
102	const policyBaseOf = (groups: BillingGroup[]): number =>
103	  groups.reduce((sum, g) => sum + g.base, 0);
104	
105	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
106	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
107	
108	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
109	  const groups = billingGroups(items);
110	  const itemsTotal = sumGroupPremiums(groups);
111	  const policyBase = policyBaseOf(groups);
112	  const loyaltyDiscount = loyaltyDiscountOf(policyBase, customer);
113	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
114	  return Math.ceil(itemsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
115	};
116	
117	type Policy = { items: Item[]; cap: number };
118	
119	const insuranceSumOf = (items: Item[]): number =>
120	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
121	
122	const isHighlyEnchantedForPayout = (item: Item): boolean =>
123	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
124	
125	const reimbursableAmount = (amount: number, item: Item): number =>
126	  isHighlyEnchantedForPayout(item) ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
127	
128	const assertNonNegativeDamage = (damage: Damage): void => {
129	  if (damage.amount < 0) {
130	    throw new Error(`Invalid negative damage amount: ${damage.amount}`);
131	  }
132	};
133	
134	const damagePayout = (damage: Damage, item: Item): number => {
135	  assertNonNegativeDamage(damage);
136	  return Math.max(0, reimbursableAmount(damage.amount, item) - DEDUCTIBLE);
137	};
138	
139	const insuredItemOf = (policy: Policy, itemType: string): Item => {
140	  const item = policy.items.find((i) => i.type === itemType);
141	  if (item === undefined) {
142	    throw new Error(`Item not in policy: ${itemType}`);
143	  }
144	  return item;
145	};
146	
147	const countByType = (entries: { type?: string; itemType?: string }[]): Map<string, number> => {
148	  const counts = new Map<string, number>();
149	  for (const e of entries) {
150	    const key = (e.type ?? e.itemType) as string;
151	    counts.set(key, (counts.get(key) ?? 0) + 1);
152	  }
153	  return counts;
154	};
155	
156	const assertDamagesCovered = (policy: Policy, incident: Incident): void => {
157	  const itemCounts = countByType(policy.items);
158	  const damageCounts = countByType(incident.damages);
159	  for (const [type, dCount] of damageCounts) {
160	    const iCount = itemCounts.get(type);
161	    if (iCount !== undefined && dCount > iCount) {
162	      throw new Error(`More ${type} damages than items insured in policy`);
163	    }
164	  }
165	};
166	
167	const incidentPayout = (policy: Policy, incident: Incident): number => {
168	  assertDamagesCovered(policy, incident);
169	  return incident.damages.reduce(
170	    (sum, d) => sum + damagePayout(d, insuredItemOf(policy, d.itemType)),
171	    0,
172	  );
173	};
174	
175	const newPolicy = (items: Item[]): Policy => ({
176	  items,
177	  cap: insuranceSumOf(items) * CAP_MULTIPLIER,
178	});
179	
180	const cappedPayout = (policy: Policy, incident: Incident): number =>
181	  Math.floor(Math.min(incidentPayout(policy, incident), policy.cap));
182	
183	const settleClaim = (policy: Policy, incident: Incident): ClaimResult => {
184	  const payout = cappedPayout(policy, incident);
185	  policy.cap -= payout;
186	  return { payout, remainingCap: policy.cap };
187	};
188	
189	export const runScenario = (scenario: Scenario): ScenarioResult => {
190	  const policies: Policy[] = [];
191	  const results = scenario.steps.map((step) => {
192	    if (step.op === "quote") {
193	      const isFollowUp = policies.length > 0;
194	      policies.push(newPolicy(step.items));
195	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
196	    }
197	    return settleClaim(policies[step.policy], step.incident);
198	  });
199	  return { results };
200	};
